import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"窝轮","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"derivatives/warrants.md","filePath":"zh-CN/derivatives/warrants.md"}'),i={name:"derivatives/warrants.md"};function h(d,a,o,n,s,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="窝轮" tabindex="-1">窝轮 <a class="header-anchor" href="#窝轮" aria-label="Permalink to &quot;窝轮&quot;">​</a></h1><p>认购证和认沽证定义、交易规则、简称含义、结算计算及参考工具。</p><h2 id="什么是窝轮" tabindex="-1">什么是窝轮 <a class="header-anchor" href="#什么是窝轮" aria-label="Permalink to &quot;什么是窝轮&quot;">​</a></h2><p>窝轮本质上是一种期权，相当于持有一种虚拟的权利。以持有人的权利而言，分为认购证和认沽证。</p><h3 id="认购证-call" tabindex="-1">认购证（Call） <a class="header-anchor" href="#认购证-call" aria-label="Permalink to &quot;认购证（Call）&quot;">​</a></h3><p>赋予持有人以行使价在特定期限内购买一定数量相关资产的权利（非责任）。看好相关资产后市时买入。</p><h3 id="认沽证-put" tabindex="-1">认沽证（Put） <a class="header-anchor" href="#认沽证-put" aria-label="Permalink to &quot;认沽证（Put）&quot;">​</a></h3><p>赋予持有人以行使价在特定期限内出售一定数量相关资产的权利（非责任）。看空相关资产后市时买入。</p><h2 id="交易规则" tabindex="-1">交易规则 <a class="header-anchor" href="#交易规则" aria-label="Permalink to &quot;交易规则&quot;">​</a></h2><h3 id="交易时段" tabindex="-1">交易时段 <a class="header-anchor" href="#交易时段" aria-label="Permalink to &quot;交易时段&quot;">​</a></h3><p>窝轮在港股持续交易时段交易，与港股交易时间一致。</p><h3 id="交易入口" tabindex="-1">交易入口 <a class="header-anchor" href="#交易入口" aria-label="Permalink to &quot;交易入口&quot;">​</a></h3><p>股票详情页进入轮证页面，点击对应窝轮，选择「买入」或「卖出」，输入价格和数量下单。</p><h3 id="支持订单类型" tabindex="-1">支持订单类型 <a class="header-anchor" href="#支持订单类型" aria-label="Permalink to &quot;支持订单类型&quot;">​</a></h3><p>限价单、市价单、条件单、策略单及长期单。</p><h3 id="最小交易单位" tabindex="-1">最小交易单位 <a class="header-anchor" href="#最小交易单位" aria-label="Permalink to &quot;最小交易单位&quot;">​</a></h3><p>按照窝轮自身的手数限制。</p><h3 id="交收规则" tabindex="-1">交收规则 <a class="header-anchor" href="#交收规则" aria-label="Permalink to &quot;交收规则&quot;">​</a></h3><p>T+0 交易，T+2 交收，均为现金结算。</p><h2 id="简称含义" tabindex="-1">简称含义 <a class="header-anchor" href="#简称含义" aria-label="Permalink to &quot;简称含义&quot;">​</a></h2><p>以 19197「华能法巴五零一购（@EC）」为例：</p><table tabindex="0"><thead><tr><th>部分</th><th>含义</th></tr></thead><tbody><tr><td>华能</td><td>相关资产为华能国际（902）</td></tr><tr><td>法巴</td><td>发行商为 BNP</td></tr><tr><td>五零一</td><td>到期日为 2005 年 1 月（具体日期需查看 APP 轮证行情页）</td></tr><tr><td>购</td><td>认购证（认沽证显示「沽」）</td></tr><tr><td>@</td><td>现金结算（* = 现货结算，$ = 现金或现货结算）</td></tr><tr><td>E</td><td>欧式备兑证（European）</td></tr><tr><td>C</td><td>认购证 Call（认沽证显示 P）</td></tr></tbody></table><h3 id="月份表示规则" tabindex="-1">月份表示规则 <a class="header-anchor" href="#月份表示规则" aria-label="Permalink to &quot;月份表示规则&quot;">​</a></h3><p>1-10 月以中文数字（一、二…十）代表，11 月以「甲」代表，12 月以「乙」代表。同一发行商同一资产同一到期月再发行的以系列编号 A、B、C 区分。</p><h2 id="轮证结算" tabindex="-1">轮证结算 <a class="header-anchor" href="#轮证结算" aria-label="Permalink to &quot;轮证结算&quot;">​</a></h2><h3 id="剩余价值计算" tabindex="-1">剩余价值计算 <a class="header-anchor" href="#剩余价值计算" aria-label="Permalink to &quot;剩余价值计算&quot;">​</a></h3><ul><li>认购证：剩余价值 =（结算价 - 行使价）÷ 换股比率。仅到期时结算价 &gt; 行使价（价内）时有效，否则为零</li><li>认沽证：剩余价值 =（行使价 - 结算价）÷ 换股比率。仅到期时结算价 &lt; 行使价（价内）时有效，否则为零</li></ul><h3 id="结算价" tabindex="-1">结算价 <a class="header-anchor" href="#结算价" aria-label="Permalink to &quot;结算价&quot;">​</a></h3><ul><li>个股窝轮：到期日前（不含到期日）5 个交易日的正股平均收市价</li><li>指数窝轮：以联交所公布的对应期货合约最终结算价为准（如恒指窝轮使用恒指期货的 EAS，即到期日当天的 5 分钟平均价）</li></ul><h2 id="关键行情字段" tabindex="-1">关键行情字段 <a class="header-anchor" href="#关键行情字段" aria-label="Permalink to &quot;关键行情字段&quot;">​</a></h2><h3 id="街货量与街货比" tabindex="-1">街货量与街货比 <a class="header-anchor" href="#街货量与街货比" aria-label="Permalink to &quot;街货量与街货比&quot;">​</a></h3><ul><li>街货量：市场上由其他投资者持有的轮证数量</li><li>街货比：投资者持有的轮证占总发行量的比例</li></ul><h3 id="换股价与换股比率" tabindex="-1">换股价与换股比率 <a class="header-anchor" href="#换股价与换股比率" aria-label="Permalink to &quot;换股价与换股比率&quot;">​</a></h3><ul><li>换股比率：多少单位的轮证可以换 1 股正股</li><li>换股价：兑换时对应正股的价格</li></ul><h2 id="参考工具" tabindex="-1">参考工具 <a class="header-anchor" href="#参考工具" aria-label="Permalink to &quot;参考工具&quot;">​</a></h2><p><a href="https://www.warrants.hsbc.com.hk/sc/tools/settlement" target="_blank" rel="noreferrer">轮证结算值计算器</a></p><p><a href="https://www.gswarrants.com.hk/tc/warrant/listing-doc" target="_blank" rel="noreferrer">轮证文件及通告查询</a></p>',37)])])}const p=t(i,[["render",h]]);export{b as __pageData,p as default};
